from urllib.parse import urlparse, urljoin
from typing import Optional

class LoginRedirect:
    def __init__(self, base_url: str, allowed_paths: list = None, route_map: dict = None):
        """
        Initialize login redirect handler with security controls.
        
        Args:
            base_url: The base URL of your application (e.g., 'https://example.com')
            allowed_paths: List of allowed relative paths for redirection
            route_map: Dictionary mapping route identifiers to actual paths
        """
        self.base_url = base_url.rstrip('/')
        self.allowed_paths = allowed_paths or [
            '/',
            '/dashboard',
            '/profile',
            '/settings',
            '/home'
        ]
        self.route_map = route_map or {
            'home': '/',
            'dashboard': '/dashboard',
            'profile': '/profile',
            'settings': '/settings',
            'user_home': '/home'
        }
    
    def is_safe_url(self, url: str) -> bool:
        """
        Validate if a URL is safe for redirection.
        
        Args:
            url: The URL to validate
            
        Returns:
            True if URL is safe, False otherwise
        """
        if not url:
            return False
        
        parsed = urlparse(url)
        
        # Reject absolute URLs with different schemes or domains
        if parsed.scheme and parsed.scheme not in ['http', 'https']:
            return False
        
        if parsed.netloc:
            base_parsed = urlparse(self.base_url)
            if parsed.netloc != base_parsed.netloc:
                return False
        
        # Check if path is in allowlist
        path = parsed.path or '/'
        return path in self.allowed_paths
    
    def get_redirect_url_from_path(self, next_url: Optional[str]) -> str:
        """
        Validate and return safe redirect URL from user-supplied path.
        
        Args:
            next_url: User-supplied next URL (from query parameter)
            
        Returns:
            Safe redirect URL (defaults to home if invalid)
        """
        if not next_url:
            return self.base_url + '/'
        
        # Parse and validate the URL
        if self.is_safe_url(next_url):
            parsed = urlparse(next_url)
            # Return the path component only, joined with base URL
            return urljoin(self.base_url, parsed.path)
        
        # Default to home if validation fails
        return self.base_url + '/'
    
    def get_redirect_url_from_route_id(self, route_id: Optional[str]) -> str:
        """
        Get redirect URL from server-side route identifier (RECOMMENDED).
        
        Args:
            route_id: Server-side route identifier
            
        Returns:
            Safe redirect URL mapped from route ID
        """
        if not route_id or route_id not in self.route_map:
            return self.base_url + '/'
        
        return self.base_url + self.route_map[route_id]
    
    def redirect_after_login(self, next_param: Optional[str] = None, 
                            route_id: Optional[str] = None,
                            use_route_id: bool = True) -> str:
        """
        Main function to get safe redirect URL after authentication.
        
        Args:
            next_param: User-supplied next parameter (from query string)
            route_id: Server-side route identifier
            use_route_id: If True, prefer route_id over next_param (more secure)
            
        Returns:
            Safe redirect URL
        """
        if use_route_id and route_id:
            return self.get_redirect_url_from_route_id(route_id)
        elif next_param:
            return self.get_redirect_url_from_path(next_param)
        elif route_id:
            return self.get_redirect_url_from_route_id(route_id)
        else:
            return self.base_url + '/'


