def example_flask_usage():
    from flask import Flask, request, redirect, session
    
    app = Flask(__name__)
    app.secret_key = 'your-secret-key'
    
    # Initialize redirect handler
    redirect_handler = LoginRedirect(
        base_url='https://example.com',
        allowed_paths=['/', '/dashboard', '/profile', '/settings', '/admin/users'],
        route_map={
            'home': '/',
            'dashboard': '/dashboard',
            'profile': '/profile',
            'settings': '/settings',
            'admin_users': '/admin/users'
        }
    )
    
    @app.route('/login', methods=['GET', 'POST'])
    def login():
        if request.method == 'POST':
            username = request.form.get('username')
            password = request.form.get('password')
            
            # Authenticate user (simplified)
            if authenticate_user(username, password):
                session['user'] = username
                
                # SECURE APPROACH 1: Use route identifier (RECOMMENDED)
                route_id = request.form.get('route_id') or session.get('intended_route')
                safe_url = redirect_handler.redirect_after_login(route_id=route_id)
                
                # SECURE APPROACH 2: Validate user-supplied URL
                # next_url = request.args.get('next')
                # safe_url = redirect_handler.redirect_after_login(next_param=next_url)
                
                return redirect(safe_url)
        
        return "Login page"
    
    @app.route('/protected')
    def protected_route():
        if 'user' not in session:
            # Store route identifier instead of full URL
            session['intended_route'] = 'dashboard'
            return redirect('/login')
        return "Protected content"
    
    def authenticate_user(username, password):
        # Placeholder authentication
        return username == 'admin' and password == 'password'
    
    return app


# Example usage with Django-like framework
def example_django_usage():
    """
    Example for Django framework
    """
    # In views.py
    from django.shortcuts import redirect
    from django.contrib.auth import authenticate, login
    from django.http import HttpRequest, HttpResponse
    
    redirect_handler = LoginRedirect(
        base_url='https://example.com',
        allowed_paths=['/', '/dashboard', '/profile'],
        route_map={
            'home': '/',
            'dashboard': '/dashboard',
            'profile': '/profile'
        }
    )
    
    def login_view(request: HttpRequest) -> HttpResponse:
        if request.method == 'POST':
            username = request.POST.get('username')
            password = request.POST.get('password')
            user = authenticate(request, username=username, password=password)
            
            if user is not None:
                login(request, user)
                
                # Use route identifier (SECURE)
                route_id = request.POST.get('route_id', 'home')
                safe_url = redirect_handler.redirect_after_login(route_id=route_id)
                
                return redirect(safe_url)
        
        return HttpResponse("Login page")


